  $invoice  = $line[2];
  $total    = $line[3];
  $ndate    = date('Y-m-d', strtotime($date));

  $result = ncmExecute('SELECT transactionId FROM transaction WHERE companyId = ? AND DATE(transactionDate) = ? AND invoiceNo = ? AND transactionTotal = ? LIMIT 5', [4452, $ndate, $invoice, $total]);

  if(gettype($result) == 'array'){
    echo gettype($result) . '<br>';
    
    if(in_array($result['transactionId'], $found)){
      $repe[] = $result['transactionId'];  
