$result = ncmExecute("SELECT * FROM transaction WHERE companyId = ? AND transactionDate BETWEEN '2022-05-01 00:00:00' AND '2022-06-31 11:59:59' ORDER BY invoiceNo DESC", [4452], false, true);

$usedNos = [];
$tTag    = "200338";

if($result){
  while (!$result->EOF) {
      $field      = $result->fields;
      $invoiceNo  = $field['invoiceNo'];
      $transID    = $field['transactionId'];
      $olltag     = [];
      
      if( in_array($invoiceNo, $usedNos) ){//si el num de factura esta repetido
        $oltag = ncmExecute("SELECT tags FROM transaction WHERE companyId = ? AND transactionId = ? LIMIT 1", [4452, $transID]);

        if($oltag){//obtengo los tags de la transaccion
          $olltag = json_decode($oltag['tags'], true);
        }

        if(!in_array($tTag, $oltag)){//si no existe el tag Soporte lo agrego
          $oltag[] = $tTag;
          
          ncmUpdate([ 'records' => ['tags' => $oltag], 'table' => 'transaction', 'where' => 'transactionId = ' . $transID . ' AND companyId = 4452' ]);
        }
      }

      $usedNos[] = $invoiceNo;

      $result->MoveNext(); 
  }
  $result->Close();

}else{

  echo 'Nothing found';
  
}


die();

